// Lấy số điện thoại khách gửi lên từ Webhook
const phoneRaw = $json.body?.phone || "";

// Giữ lại CHỈ chữ số
let digits = phoneRaw.replace(/\D/g, ""); // "0772990730", "84772990730", ...

if (!digits) {
  return [{ phone: null }];
}

// Nếu bắt đầu bằng 0  → đổi thành 84xxxxxxx
if (digits.startsWith("0")) {
  digits = "84" + digits.slice(1); // "84772990730"
}

// Nếu đã bắt đầu bằng 84 (hoặc nhập sẵn 84xxxx) thì giữ 84 và bỏ 84 đi để lấy phần sau
if (digits.startsWith("84")) {
  digits = digits.slice(2); // "772990730"
}

// Đảm bảo còn lại là 9 số → mobile VN
digits = digits.padStart(9, "0"); // "772990730"

// Format lại dạng +84 XXX XXX XXX
const formatted = `+84 ${digits.slice(0, 3)} ${digits.slice(3, 6)} ${digits.slice(6, 9)}`;

// Kết quả trả ra cho node sau
return [
  {
    phone: formatted, // "+84 772 990 730"
  },
];

// -------- Helpers --------

function deliveryStatusVN(status) {
  if (!status) return "Đang cập nhật";
  const s = status.toString().trim().toLowerCase();

  if (s === "02_changes_requested") return "Đã tiếp nhận";
  if (s === "01_in_progress") return "Đang xử lý giao hàng";
  if (s === "1_done") return "Đã giao hàng";

  return "Đang cập nhật";
}

function cleanStaffName(raw) {
  if (!raw) return null;
  const parts = raw.split(",");
  return parts[parts.length - 1].trim();
}

function formatDateVN(dateString) {
  if (!dateString) return null;
  const d = dateString.split(" ")[0];
  const [year, month, day] = d.split("-");
  return `${day}/${month}/${year}`;
}

// -------- Main --------

const items = $input.all();

const productLines = [];
const deliveryTasks = [];

for (const item of items) {
  const r = item.json;

  if (r.product_id) {
    // Sale Order Line
    productLines.push(r);
  } else if (r.x_studio_ma_don_hang) {
    // Field Service / Delivery Task
    deliveryTasks.push(r);
  }
}

// 1) Gom sản phẩm theo product_id (KHÔNG cộng dồn, luôn lấy qty của dòng)
const productMap = {};

for (const line of productLines) {
  const prod = line.product_id || [];
  const prodId = prod[0];
  const prodName = prod[1] || null;
  const qty = Number(line.product_uom_qty || 0);

  if (!prodId) continue;

  if (!productMap[prodId]) {
    productMap[prodId] = {
      productId: prodId,
      name: prodName,
      quantity: qty,  // lấy thẳng qty của dòng
    };
  } else {
    // Nếu có nhiều dòng trùng product, ưu tiên qty “lớn nhất” cho an toàn
    productMap[prodId].quantity = Math.max(productMap[prodId].quantity, qty);
    // Hoặc nếu muốn chỉ lấy dòng cuối: productMap[prodId].quantity = qty;
  }
}

const products = Object.values(productMap);

// 2) Xử lý các lần giao
let deliveries = deliveryTasks.map((r) => {
  const rawDate = r.planned_date_begin || null;
  const dateObj = rawDate ? new Date(rawDate.replace(" ", "T")) : null;

  return {
    id: r.id,
    orderCode: r.x_studio_ma_don_hang || null,
    phone: r.partner_phone || null,
    customerName: Array.isArray(r.partner_id) ? r.partner_id[1] : null,
    staffName: Array.isArray(r.x_studio_nhan_vien)
      ? cleanStaffName(r.x_studio_nhan_vien[1])
      : null,
    status: deliveryStatusVN(r.x_studio_status_giao_hng),
    rawStatus: r.x_studio_status_giao_hng || null,
    deliveryDate: formatDateVN(rawDate),
    deliveryDateRaw: rawDate,
    deliveryDateObj: dateObj,
  };
});

// Sort lần giao theo ngày
deliveries = deliveries.sort((a, b) => {
  if (!a.deliveryDateObj && !b.deliveryDateObj) return 0;
  if (!a.deliveryDateObj) return 1;
  if (!b.deliveryDateObj) return -1;
  return a.deliveryDateObj - b.deliveryDateObj;
});

// Thông tin chung
let orderCode = null;
let customerName = null;
let phone = null;

if (deliveries.length > 0) {
  orderCode = deliveries[0].orderCode;
  customerName = deliveries[0].customerName;
  phone = deliveries[0].phone;
} else if (productLines.length > 0) {
  const r = productLines[0];
  orderCode = r.origin || null;
  customerName = Array.isArray(r.partner_id) ? r.partner_id[1] : null;
}

// Output cho FE
return [
  {
    success: true,
    orderCode,
    customerName,
    phone,
    products,
    deliveries,
  },
];

// Run once for all items
const seen = new Set();
const output = [];

for (const item of items) {
    const pidArr = item.json.product_id;

    // Safety check: ensure array exists & has name part
    if (!Array.isArray(pidArr) || typeof pidArr[1] !== "string") {
        continue; // skip invalid rows
    }

    const pid = pidArr[0];
    const name = pidArr[1].toLowerCase();

    // 1) Filter OUT "Order Value"
    if (name.includes("order value")) {
        continue;
    }

    // 2) Remove duplicates by product_id integer
    if (seen.has(pid)) {
        continue;
    }

    seen.add(pid);
    output.push(item);
}

return output;
